import React, { createContext, useState, useEffect, useContext, useCallback } from 'react';
import authService, { setLogoutCallback } from '../services/authService';

const AuthContext = createContext();

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  const logout = async () => {
    try {
      await authService.logout();
    } catch (error) {
      console.error('Erro no logout:', error);
    } finally {
      setUser(null);
      setIsAuthenticated(false);
    }
  };

  const loadUserProfile = useCallback(async () => {
    console.log('[AuthContext] Carregando perfil completo do usuário...');
    try {
      const profileResponse = await authService.getProfile();
      // Removido console.log com dados sensíveis por segurança

      if (profileResponse && profileResponse.user) {
        setUser(profileResponse.user);
        return profileResponse.user;
      }
    } catch (error) {
      console.error('[AuthContext] Erro ao carregar perfil:', error);
    }
    return null;
  }, []);

  const checkAuthStatus = useCallback(async () => {
    console.log('[AuthContext] Iniciando verificação de autenticação...');
    try {
      const response = await authService.checkSession();
      console.log('[AuthContext] Resposta da sessão:', response.data);

      // Backend retorna: { data: { logged_in: boolean, user: object } }
      if (response.data && response.data.data && response.data.data.logged_in && response.data.data.user) {
        console.log('[AuthContext] Usuário autenticado, carregando perfil completo...');
        setUser(response.data.data.user);
        setIsAuthenticated(true);
      } else {
        console.log('[AuthContext] Usuário não autenticado');
        setIsAuthenticated(false);
      }
    } catch (error) {
      console.error('[AuthContext] Erro ao verificar autenticação:', error);
      setIsAuthenticated(false);
    } finally {
      console.log('[AuthContext] Finalizando verificação, setLoading(false)');
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    console.log('[AuthContext] Componente montado, iniciando verificação...');

    // Registrar callback de logout no interceptador
    setLogoutCallback(() => {
      setUser(null);
      setIsAuthenticated(false);
    });

    // Verificar autenticação apenas uma vez na montagem
    const verifyAuth = async () => {
      try {
        await checkAuthStatus();
      } catch (error) {
        console.error('[AuthContext] Erro na verificação inicial:', error);
        setLoading(false);
        setIsAuthenticated(false);
      }
    };

    verifyAuth();
  }, [checkAuthStatus]); // Adicionada dependência de checkAuthStatus

  const login = async (email, password) => {
    console.log('[AuthContext] Iniciando login para:', email);
    try {
      const response = await authService.login({ email, password });
      console.log('[AuthContext] Resposta do login:', response.data);

      // Verificar se o login foi bem-sucedido (backend retorna message e user)
      if (response.data && response.data.user && response.data.message === 'Login realizado com sucesso') {
        console.log('[AuthContext] Login bem-sucedido, definindo usuário...');
        setUser(response.data.user);
        setIsAuthenticated(true);

        // Aguardar um pouco antes de verificar a sessão para evitar race condition
        setTimeout(async () => {
          try {
            console.log('[AuthContext] Verificando sessão após login...');
            await checkAuthStatus();
          } catch (error) {
            console.log('[AuthContext] Erro na verificação pós-login (ignorado):', error.message);
            // Ignorar erros de verificação pós-login para não afetar a experiência do usuário
          }
        }, 1000);

        return { success: true };
      }

      console.log('[AuthContext] Login falhou - dados inválidos');
      return { success: false, message: response.data?.message || 'Credenciais inválidas' };
    } catch (error) {
      console.error('[AuthContext] Erro no login:', error);
      return { success: false, message: error.message || 'Erro no login' };
    }
  };

  const updateProfile = async (profileData) => {
    try {
      const response = await authService.updateProfile(profileData);
      if (response.user) {
        setUser(response.user);
        return response.user;
      }
      throw new Error('Erro ao atualizar perfil');
    } catch (error) {
      console.error('[AuthContext] Erro ao atualizar perfil:', error);
      throw error;
    }
  };

  const value = {
    user,
    setUser,
    loading,
    isAuthenticated,
    login,
    logout,
    checkAuthStatus,
    loadUserProfile,
    updateProfile
  };

  return (
    <AuthContext.Provider value={value}>
      {children}
    </AuthContext.Provider>
  );
};

export { AuthContext };
export default AuthContext;
